      "source": "// A-2: 배치 감정 분석 — 여러 리뷰를 JSON 배열로 받기\nconst reviews = [\n  \"직원분이 너무 친절해서 기분 좋았어요!\",\n  \"음식이 짜고 양도 적어서 실망했습니다.\",\n  \"위치는 좋은데 주차가 불편해요.\",\n  \"가격 대비 훌륭합니다. 강추!\",\n  \"주문한 것과 다른 메뉴가 왔어요. 환불 요청했습니다.\",\n  \"보통이에요. 특별한 건 없지만 나쁘지도 않아요.\",\n  \"분위기가 아늑하고 디저트가 맛있어요 💕\",\n  \"30분 넘게 기다렸는데 사과도 없었어요.\",\n];\n\nconst response = await chat({\n  provider: \"gemini\",\n  messages: [\n    {\n      role: \"system\",\n      content: `너는 감정 분석 API야. 리뷰 목록을 받으면 JSON 배열로만 답해.\n다른 텍스트 없이 순수 JSON 만 출력해.\n\n각 항목 형식:\n{\n  \"text\": \"원본 리뷰 (앞 20자...)\",\n  \"sentiment\": \"긍정\" | \"부정\" | \"중립\",\n  \"confidence\": 0.0 ~ 1.0,\n  \"keywords\": [\"키워드1\", \"키워드2\"]\n}`,\n    },\n    {\n      role: \"user\",\n      content: `아래 ${reviews.length}개 리뷰를 분석해줘:\\n${reviews.map((r, i) => `${i + 1}. ${r}`).join(\"\\n\")}`,\n    },\n  ],\n});\n\nconsole.log(\"📊 배치 분석 결과:\");\nconsole.log(response.text);\n\n// JSON 파싱 + 통계\ntry {\n  const cleaned = response.text.replace(/```json?\\n?/g, \"\").replace(/```/g, \"\").trim();\n  const results = JSON.parse(cleaned);\n\n  const counts = { 긍정: 0, 부정: 0, 중립: 0 };\n  for (const r of results) {\n    counts[r.sentiment as keyof typeof counts]++;\n  }\n\n  console.log(\"\\n── 감정 분포 ──\");\n  console.log(`😊 긍정: ${counts[\"긍정\"]}건 (${Math.round((counts[\"긍정\"] / results.length) * 100)}%)`);\n  console.log(`😠 부정: ${counts[\"부정\"]}건 (${Math.round((counts[\"부정\"] / results.length) * 100)}%)`);\n  console.log(`😐 중립: ${counts[\"중립\"]}건 (${Math.round((counts[\"중립\"] / results.length) * 100)}%)`);\n\n  // 전체 키워드 빈도\n  const kwCount: Record<string, number> = {};\n  for (const r of results) {\n    for (const kw of r.keywords) {\n      kwCount[kw] = (kwCount[kw] || 0) + 1;\n    }\n  }\n  const topKw = Object.entries(kwCount)\n    .sort((a, b) => b[1] - a[1])\n    .slice(0, 5);\n  console.log(\"\\n🔤 상위 키워드:\", topKw.map(([k, v]) => `${k}(${v})`).join(\", \"));\n} catch {\n  console.log(\"⚠️ JSON 파싱 실패 — 다시 실행해보세요!\");\n}",
