"🏛️\", 문화: \"🎭\", 스포츠: \"⚽\", 과학: \"🔬\"\n  };\n\n  for (const [cat, items] of Object.entries(grouped)) {\n    console.log(`\\n${icons[cat] || \"📰\"} ${cat} (${items.length}건)`);\n    items.forEach(item =>\n      console.log(`   • ${item.title} (확신: ${(item.confidence * 100).toFixed(0)}%)`)\n    );\n  }\n} catch {\n  console.log(\"원본 응답:\", res.text);\n}",
